export async function fetchData(url: string): Promise<string> {
  const response = await fetch(url);

  if (!response.ok) {
    throw new Error(`HTTP ${response.status}: ${response.statusText}`);
  }

  return await response.text();
}

import { proxyActivities } from '@temporalio/workflow';
import type * as activities from './activities';

const { fetchData } = proxyActivities<typeof activities>({
  startToCloseTimeout: '30 seconds'
});

export async function FetchUrlWorkflow(url: string): Promise<string> {
  return await fetchData(url);
}

import { NativeConnection, Worker } from '@temporalio/worker';
import * as activities from './activities';

function requireEnv(name: string): string {
  const value = process.env[name];
  if (!value) {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

async function run(): Promise<void> {
  const connection = await NativeConnection.connect({
    address: requireEnv('TEMPORAL_ADDRESS'),
    tls: true,
    apiKey: requireEnv('TEMPORAL_API_KEY')
  });

  const worker = await Worker.create({
    connection,
    namespace: requireEnv('TEMPORAL_NAMESPACE'),
    taskQueue: 'fetch-url-ts',
    workflowsPath: require.resolve('./workflows'),
    activities
  });

  await worker.run();
}

run().catch((error) => {
  console.error(error);
  process.exit(1);
});

import { Connection, Client } from '@temporalio/client';
import { FetchUrlWorkflow } from './workflows';

function requireEnv(name: string): string {
  const value = process.env[name];
  if (!value) {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

async function run(): Promise<void> {
  const runId = requireEnv('ZEALT_RUN_ID');
  const connection = await Connection.connect({
    address: requireEnv('TEMPORAL_ADDRESS'),
    tls: true,
    apiKey: requireEnv('TEMPORAL_API_KEY')
  });

  const client = new Client({
    connection,
    namespace: requireEnv('TEMPORAL_NAMESPACE')
  });

  const result = await client.workflow.execute(FetchUrlWorkflow, {
    args: ['https://api.github.com/zen'],
    taskQueue: 'fetch-url-ts',
    workflowId: `fetch-wf-${runId}`
  });

  console.log(result);
}

run().catch((error) => {
  console.error(error);
  process.exit(1);
});
